('Банши', 'Medium', 'undead', 'chaotic evil', 4, 1100, 12, NULL, 58, '13d8', '{"fly":40}',
 '{"str":1,"dex":14,"con":10,"int":12,"wis":11,"cha":17}',
 '[{"name":"Обнаружение жизни","description":"Банши магически чувствует присутствие живых существ в 5 милях. Она знает направление, но не точное местонахождение."},{"name":"Бестелесное движение","description":"Банши может проходить сквозь существ и объекты, воспринимая их как сложную местность."}]',
 '[{"name":"Разрушительное прикосновение","description":"Рукопашная атака заклинанием: +4 к попаданию, досягаемость 5 фт., одна цель. Урон: 12 (3d6+2) некротического урона."},{"name":"Вой смерти","description":"Банши издаёт магический вой. Существа в 30 фт. должны пройти спасбросок Телосложения СЛ 13 или упасть до 0 HP. Уже умирающие цели: при провале провалить два броска смерти, при успехе — один. Иммунитет у нежити и конструктов."},{"name":"Жуткий вой","description":"Каждое существо в 30 фт. должно пройти спасбросок Мудрости СЛ 13 или испугаться до конца следующего хода банши."}]');

-- SPELLS (SRD 5.1 - 30 заклинаний)
INSERT INTO spells (name, level, school, casting_time, range, components, duration, concentration, ritual, description, higher_levels, classes) VALUES
('Огненный снаряд', 0, 'evocation', '1 действие', '120 футов', '{"v":true,"s":true,"m":null}', 'Мгновенно', false, false,
 'Вы бросаете сгусток огня в существо или предмет в пределах дистанции. Совершите дальнобойную атаку заклинанием по цели. При попадании цель получает 1d10 урона огнём.',
 'Урон заклинания увеличивается на 1d10, когда вы достигаете 5-го (2d10), 11-го (3d10) и 17-го (4d10) уровня.',
 '["wizard","sorcerer"]'),

('Магическая стрела', 1, 'evocation', '1 действие', '120 футов', '{"v":true,"s":true,"m":null}', 'Мгновенно', false, false,
 'Вы создаёте три светящихся дротика из магической силы. Каждый дротик попадает в существо на ваш выбор в пределах дистанции. Дротик наносит 1d4+1 урона силовым полем. Все дротики летят одновременно, и вы можете направить их в одну или в разные цели.',
 'Если вы накладываете это заклинание, используя слот 2 уровня или выше, заклинание создаёт ещё один дротик за каждый уровень слота выше 1-го.',
 '["wizard","sorcerer"]'),

('Горящие руки', 1, 'evocation', '1 действие', 'Само (конус 15 фт.)', '{"v":true,"s":true,"m":null}', 'Мгновенно', false, false,
 'Вытянув большие пальцы рук и растопырив пальцы, вы выпускаете тонкий веер пламени. Все существа в конусе 15 футов должны пройти спасбросок Ловкости. При провале существо получает 3d6 урона огнём, при успехе — половину.',
 'При использовании слота 2 уровня и выше, урон увеличивается на 1d6 за каждый уровень слота выше 1-го.',
 '["wizard","sorcerer"]'),

('Огненный шар', 3, 'evocation', '1 действие', '150 футов', '{"v":true,"s":true,"m":"крошечный шарик из гуано летучей мыши и серы"}', 'Мгновенно', false, false,
 'Яркая вспышка света летит из вашего указательного пальца к точке в пределах дистанции и с рёвом расцветает в огненный взрыв. Все существа в сфере радиусом 20 футов с центром в этой точке должны пройти спасбросок Ловкости. При провале существо получает 8d6 урона огнём, при успехе — половину.',
 'При использовании слота 4 уровня и выше, урон увеличивается на 1d6 за каждый уровень слота выше 3-го.',
 '["wizard","sorcerer"]'),

('Лечение ран', 1, 'evocation', '1 действие', 'Касание', '{"v":true,"s":true,"m":null}', 'Мгновенно', false, false,
 'Существо, которого вы касаетесь, восстанавливает количество хит-пойнтов, равное 1d8 + ваш модификатор заклинательной характеристики.',
 'При использовании слота 2 уровня и выше, лечение увеличивается на 1d8 за каждый уровень слота выше 1-го.',
 '["cleric","druid","paladin","ranger","bard"]'),

('Благословение', 1, 'enchantment', '1 действие', '30 футов', '{"v":true,"s":true,"m":"капля святой воды"}', 'Концентрация, вплоть до 1 минуты', true, false,
 'Вы благословляете до трёх существ на ваш выбор в пределах дистанции. Пока заклинание активно, каждый раз, когда цель совершает бросок атаки или спасбросок, она может бросить к4 и прибавить выпавшее к броску.',
 'При использовании слота 2 уровня и выше, вы можете сделать целью ещё одно существо за каждый уровень слота выше 1-го.',
 '["cleric","paladin"]'),

('Щит веры', 1, 'abjuration', '1 бонусное действие', '60 футов', '{"v":true,"s":true,"m":"небольшой клочок пергамента со священным текстом"}', 'Концентрация, вплоть до 10 минут', true, false,
 'Мерцающее поле магической энергии окружает выбранное вами существо в пределах дистанции, давая ему бонус +2 к КД на время действия заклинания.',
 NULL, '["cleric","paladin"]'),

('Колдовской заряд', 0, 'evocation', '1 действие', '120 футов', '{"v":true,"s":true,"m":null}', 'Мгновенно', false, false,
 'Вы направляете иглу разрушительной силы от вашего пальца в существо, которое вы видите в пределах дистанции. Совершите дальнобойную атаку заклинанием по существу. При попадании оно получает 1d10 урона некротической энергии.',
 'Урон заклинания увеличивается на 1d10 при достижении 5-го (2d10), 11-го (3d10) и 17-го (4d10) уровня.',
 '["warlock"]'),

('Шоковый захват', 0, 'evocation', '1 действие', 'Касание', '{"v":true,"s":true,"m":null}', 'Мгновенно', false, false,
 'Молния вспыхивает из вашей руки, поражая существо, которого вы пытаетесь коснуться. Совершите рукопашную атаку заклинанием по цели. Вы совершаете этот бросок атаки с преимуществом, если цель носит доспехи из металла. При попадании цель получает 1d8 урона молнией, и не может совершать реакций до начала следующего хода.',
 'Урон заклинания увеличивается на 1d8 при достижении 5-го (2d8), 11-го (3d8) и 17-го (4d8) уровня.',
 '["wizard","sorcerer"]'),

('Свет', 0, 'evocation', '1 действие', 'Касание', '{"v":true,"s":false,"m":"светлячок или фосфоресцирующий мох"}', '1 час', false, false,
 'Вы касаетесь одного предмета, размером не больше 10 футов в поперечнике. Пока заклинание активно, этот предмет испускает яркий свет в радиусе 20 футов и тусклый свет в пределах ещё 20 футов. Свет может быть любого цвета, который вы выберете.',
 NULL, '["wizard","sorcerer","cleric","bard"]'),

('Ледяной нож', 1, 'conjuration', '1 действие', '60 футов', '{"v":false,"s":true,"m":"капля воды или кусочек льда"}', 'Мгновенно', false, false,
 'Вы метаете осколок льда в существо в пределах дистанции. Совершите дальнобойную атаку заклинанием по цели. При попадании цель получает 1d10 колющего урона. Попадёте вы или промахнётесь, сразу после атаки осколок взрывается. Цель и каждое существо в 5 футах от точки взрыва должны пройти спасбросок Ловкости СЛ 13, при провале получая 2d6 урона холодом.',
 'При использовании слота 2 уровня и выше, урон холодом увеличивается на 1d6 за каждый уровень слота выше 1-го.',
 '["wizard","sorcerer","druid"]'),

('Стрела кислоты', 2, 'evocation', '1 действие', '90 футов', '{"v":true,"s":true,"m":"порошок ревеня и желудок живоглота"}', 'Мгновенно', false, false,
 'Зеленовато-жёлтая стрела кислоты летит к цели в пределах дистанции и взрывается в брызги кислоты. Совершите дальнобойную атаку заклинанием по существу. При попадании цель получает 4d4 урона кислотой немедленно и 2d4 урона кислотой в конце следующего хода. При промахе стрела брызгает кислотой на короткое расстояние, нанося цели 2d4 урона кислотой.',
 'При использовании слота 3 уровня и выше, урон увеличивается на 1d4 за каждый уровень слота выше 2-го.',
 '["wizard"]'),

('Невидимость', 2, 'illusion', '1 действие', 'Касание', '{"v":true,"s":true,"m":"ресница, завёрнутая в кусочек гуммиарабика"}', 'Концентрация, вплоть до 1 часа', true, false,
 'Существо, которого вы касаетесь, становится невидимым до окончания действия заклинания. Всё, что цель несёт или носит, невидимо, пока находится у неё. Заклинание заканчивается, если цель атакует или накладывает заклинание.',
 'При использовании слота 3 уровня и выше, вы можете сделать целью ещё одно существо за каждый уровень слота выше 2-го.',
 '["wizard","sorcerer","bard","warlock","ranger"]'),

('Удар охотника', 1, 'divination', '1 бонусное действие', 'Само', '{"v":true,"s":false,"m":null}', 'Концентрация, вплоть до 1 часа', true, false,
 'До конца заклинания ваша атака оружием наносит выбранному вами существу дополнительный урон 1d6. Также, пока заклинание активно, у вас есть преимущество на проверки Мудрости (Выживание) по поиску следов цели.',
 'При использовании слота 3 уровня, дополнительный урон увеличивается до 2d6. При использовании слота 5 уровня — до 3d6.',
 '["ranger"]'),

('Паутина', 2, 'conjuration', '1 действие', '60 футов', '{"v":true,"s":true,"m":"кусочек паутины"}', 'Концентрация, вплоть до 1 часа', true, false,
 'Вы вызываете большую массу густой клейкой паутины в точке по вашему выбору в пределах дистанции. Паутина заполняет куб 20 футов в этой точке на всё время заклинания. Паутина является сложной местностью и слегка засвечивает свой район. Если паутина не прикреплена к двум твёрдым поверхностям или не растёт на полу, стенах или потолке, она рушится сама по себе, и заклинание заканчивается в конце следующего хода заклинателя.',
 NULL, '["wizard","sorcerer","druid"]'),

('Конфигурация', 3, 'transmutation', '1 действие', '150 футов', '{"v":true,"s":true,"m":null}', 'Концентрация, вплоть до 1 минуты', true, false,
 'Выберите существо в пределах дистанции. Цель должна пройти спасбросок Мудрости. При провале цель становится Очарованной вами на всё время заклинания. Пока цель очарована таким образом, она не может предпринимать реакции, и в своих ходах может либо совершить действие, либо бонусное действие — не оба.',
 NULL, '["wizard","sorcerer","bard"]'),

('Защита от добра и зла', 1, 'abjuration', '1 действие', 'Касание', '{"v":true,"s":true,"m":"святая вода или порошок серебра и железа"}', 'Концентрация, вплоть до 10 минут', true, false,
 'Пока заклинание активно, одно согласное существо, которого вы касаетесь, защищено от следующих видов существ: аберрации, небожители, элементали, феи, демоны и нежить. Защита даёт несколько преимуществ. Существа перечисленных видов совершают броски атаки против цели с помехой. Цель не может быть Очарована, Испугана или Одержима такими существами.',
 NULL, '["cleric","paladin","wizard","warlock","druid"]'),

('Магический замок', 2, 'abjuration', '1 действие', 'Касание', '{"v":true,"s":true,"m":"золотая пыль стоимостью не менее 25 зм"}', 'До рассеивания', false, false,
 'Вы касаетесь закрытой двери, окна, ворот, сундука или другого прохода и запечатываете его магией. Пока заклинание активно, объект запечатан намертво. Заклинание Взлом немедленно снимает это заклинание. Иначе это заклинание действует до уничтожения.',
 NULL, '["wizard"]'),

('Молния', 3, 'evocation', '1 действие', 'Само (линия 100 фт.)', '{"v":true,"s":true,"m":"кусочек меха и стержень из янтаря, хрусталя или стекла"}', 'Мгновенно', false, false,
 'Разряд молнии образует линию 100 футов длиной и 5 футов шириной в указанном вами направлении. Все существа в линии должны пройти спасбросок Ловкости. При провале существо получает 8d6 урона молнией, при успехе — половину.',
 'При использовании слота 4 уровня и выше, урон увеличивается на 1d6 за каждый уровень слота выше 3-го.',
 '["wizard","sorcerer","druid"]'),

('Стена огня', 4, 'evocation', '1 действие', '120 футов', '{"v":true,"s":true,"m":"небольшой кусочек фосфора"}', 'Концентрация, вплоть до 1 минуты', true, false,
 'Вы создаёте стену огня на твёрдой поверхности в пределах дистанции. Стена может быть не более 60 футов в длину, 20 футов в высоту и 1 фут в толщину, или круглой с диаметром до 20 футов, 20 футов в высоту и 1 фут в толщину. Стена непроходима и дает яркий свет в 60 футах и тусклый свет в ещё 60 футах.',
 'При использовании слота 5 уровня и выше, урон увеличивается на 1d8 за каждый уровень слота выше 4-го.',
 '["wizard","sorcerer","druid"]'),

('Воскрешение', 5, 'necromancy', '1 час', 'Касание', '{"v":true,"s":true,"m":"алмаз стоимостью не менее 500 зм"}', 'Мгновенно', false, false,
 'Вы возвращаете к жизни мёртвое существо, которого касаетесь, при условии, что оно мертво не более 10 дней. Если душа существа свободна и готова вернуться, существо оживает с 1 хит-пойнтом. Это заклинание нейтрализует все яды и исцеляет немагические болезни. Это заклинание закрывает все смертельные раны.',
 NULL, '["cleric","druid","bard","paladin"]'),

('Оковы', 0, 'transmutation', '1 действие', 'Касание', '{"v":false,"s":true,"m":null}', 'До 1 минуты', false, false,
 'Выберите небольшой предмет в пределах дистанции. Предмет поднимается вертикально вверх на 3 фута, а затем зависает там на время действия заклинания. Предмет может быть перемещён рукой.',
 NULL, '["druid","wizard","sorcerer","warlock","cleric"]'),

('Дружелюбный огонь', 0, 'evocation', '1 действие', '60 футов', '{"v":true,"s":true,"m":null}', 'Мгновенно', false, false,
 'Небольшой огонёк мерцает перед существом по вашему выбору в пределах дистанции. Цель должна пройти спасбросок Ловкости. При провале цель получает 1d8 урона огнём.',
 'Урон заклинания увеличивается на 1d8 при достижении 5-го (2d8), 11-го (3d8) и 17-го (4d8) уровня.',
 '["cleric","druid"]'),

('Погружение в сон', 1, 'enchantment', '1 действие', '90 футов', '{"v":true,"s":true,"m":"щепотка мелкого песка, лепестки роз или сверчок"}', 'Мгновенно', false, false,
 'Это заклинание погружает существ в магический сон. Бросьте 5d8; итог — это количество хитов существ, на которых может подействовать это заклинание. Существа в радиусе 20 футов от точки по вашему выбору в пределах дистанции затрагиваются в порядке возрастания их текущих хитов.',
 'При использовании слота 2 уровня и выше, бросайте дополнительно 2d8 за каждый уровень слота выше 1-го.',
 '["wizard","sorcerer","bard"]'),

('Сфера тьмы', 2, 'illusion', '1 действие', '60 футов', '{"v":true,"s":false,"m":"летучья шерсть и капля смолы"}', 'Концентрация, вплоть до 10 минут', true, false,
 'Магическая тьма распространяется от точки по вашему выбору в пределах дистанции, заполняя сферу радиусом 15 футов. Тьма распространяется за углы. Существо с тёмным зрением не может видеть в этой тьме, а немагический свет не может её осветить.',
 NULL, '["wizard","sorcerer","warlock"]'),

('Призыв животного', 8, 'conjuration', '1 действие', '60 футов', '{"v":true,"s":true,"m":null}', 'Концентрация, вплоть до 1 часа', true, false,
 'Вы вызываете духов природы, принимающих облик зверей и появляющихся в свободных пространствах по вашему выбору в пределах дистанции. Если вы выбрали зверя с показателем опасности 2 или меньше, вы можете создать не более 8 таких существ. При ПО 1 или меньше вы можете создать 16 существ.',
 NULL, '["druid"]'),

('Слово силы Убей', 9, 'enchantment', '1 действие', '60 футов', '{"v":true,"s":false,"m":null}', 'Мгновенно', false, false,
 'Вы произносите слово силы, способное сломить волю к жизни одного существа, видимого вами в пределах дистанции, заставляя его пасть замертво. Если у существа 100 хитов или меньше, оно умирает. Иначе заклинание не имеет эффекта.',
 NULL, '["wizard","sorcerer","warlock","bard"]'),

('Телепортация', 7, 'conjuration', '1 действие', '10 футов', '{"v":true,"s":false,"m":null}', 'Мгновенно', false, false,
 'Это заклинание мгновенно переносит вас и до восьми согласных существ, которых вы видите в пределах дистанции, или один объект, видимый вами в пределах дистанции, на выбранный вами пункт назначения.',
 NULL, '["wizard","sorcerer","bard"]'),

('Временная остановка', 9, 'transmutation', '1 действие', 'Само', '{"v":true,"s":false,"m":null}', 'Мгновенно', false, false,
 'Вы ненадолго останавливаете ход времени для всех, кроме себя. Для других существ время перестаёт течь, тогда как для вас оно идёт обычно. Совершите 1d4+1 ходов.',
 NULL, '["wizard"]'),

('Полёт', 3, 'transmutation', '1 действие', 'Касание', '{"v":true,"s":true,"m":"крылышко летучей мыши или птицы"}', 'Концентрация, вплоть до 10 минут', true, false,
 'Вы касаетесь согласного существа. Цель получает скорость полёта 60 футов на время действия заклинания. Когда заклинание заканчивается, цель падает, если всё ещё в воздухе, если только она не может остановить падение.',
 'При использовании слота 4 уровня и выше, вы можете сделать целью ещё одно существо за каждый уровень слота выше 3-го.',
 '["wizard","sorcerer","warlock"]');

-- LOOT ITEMS (SRD 5.1)
INSERT INTO loot_items (name, type, rarity, requires_attunement, weight, cost_gp, description, properties) VALUES
('+1 Длинный меч', 'weapon', 'uncommon', false, 3, 1000, 'Этот магический длинный меч даёт бонус +1 к броскам атаки и урона.', '["+1 к атаке и урону"]'),
('+2 Длинный меч', 'weapon', 'rare', false, 3, 4000, 'Этот магический длинный меч даёт бонус +2 к броскам атаки и урона.', '["+2 к атаке и урону"]'),
('+3 Длинный меч', 'weapon', 'very_rare', false, 3, 16000, 'Этот магический длинный меч даёт бонус +3 к броскам атаки и урона.', '["+3 к атаке и урону"]'),
('Зелье лечения', 'potion', 'common', false, 0.5, 50, 'Персонаж, выпивший это красноватое зелье, восстанавливает 2d4+2 хит-пойнтов. Выпить зелье или дать его другому персонажу — это действие.', '["Восстанавливает 2d4+2 HP"]'),
('Зелье большого лечения', 'potion', 'uncommon', false, 0.5, 150, 'Персонаж, выпивший это зелье, восстанавливает 4d4+4 хит-пойнтов.', '["Восстанавливает 4d4+4 HP"]'),
('Зелье превосходного лечения', 'potion', 'rare', false, 0.5, 500, 'Персонаж, выпивший это зелье, восстанавливает 8d4+8 хит-пойнтов.', '["Восстанавливает 8d4+8 HP"]'),
('Зелье величайшего лечения', 'potion', 'very_rare', false, 0.5, 1350, 'Персонаж, выпивший это зелье, восстанавливает 10d4+20 хит-пойнтов.', '["Восстанавливает 10d4+20 HP"]'),
('Зелье невидимости', 'potion', 'very_rare', false, 0.5, 180, 'Этот зелье с переливающейся жидкостью кажется пустым. Выпив его, вы становитесь невидимым на 1 час. Эффект заканчивается раньше, если вы атакуете или накладываете заклинание.', '["Невидимость на 1 час"]'),
('Зелье силы облака', 'potion', 'very_rare', false, 0.5, 4000, 'Выпив это зелье, вы получаете силу 27 на 1 час.', '["СИЛ 27 на 1 час"]'),
('Амулет здоровья', 'wondrous', 'rare', true, 1, 8000, 'Пока этот амулет настроен, ваш показатель Телосложения равен 19. Амулет не действует если ваш показатель Телосложения равен или выше 19.', '["ТЕЛ 19","Требует настройки"]'),
('Кольцо защиты', 'ring', 'rare', true, 0, 3500, 'Пока кольцо надето, вы получаете бонус +1 к КД и спасброскам.', '["+1 КД","+1 ко всем спасброскам","Требует настройки"]'),
('Кольцо устойчивости', 'ring', 'rare', true, 0, 1000, 'Нося это кольцо, вы получаете устойчивость к одному виду урона. Тип урона определяется мастером или бросается случайно.', '["Устойчивость к одному виду урона","Требует настройки"]'),
('Плащ защиты', 'wondrous', 'uncommon', true, 1, 3500, 'Вы получаете бонус +1 к КД и спасброскам, пока носите этот плащ.', '["+1 КД","+1 ко всем спасброскам","Требует настройки"]'),
('Сапоги эльфийского хода', 'wondrous', 'uncommon', true, 2, 2500, 'Нося эти сапоги, ваши шаги не издают звука, независимо от поверхности, по которой вы ходите. Вы также совершаете с преимуществом проверки Ловкости (Скрытность).', '["Бесшумное передвижение","Преимущество на скрытность","Требует настройки"]'),
('Мешочек Колдуна', 'wondrous', 'uncommon', false, 15, 500, 'Этот мешок имеет внутреннее пространство значительно больше его внешних размеров. Он может хранить до 500 фунтов, не превышая 64 кубических фута.', '["Вместимость: 500 фунтов / 64 куб. фута"]'),
('Шляпа маскировки', 'wondrous', 'common', true, 0, 600, 'Пока вы носите эту шляпу, вы можете использовать действие, чтобы наложить на себя заклинание Маскировка по желанию.', '["Маскировка по желанию","Требует настройки"]'),
('Трубка дыма чудес', 'wondrous', 'common', true, 0, 300, 'Пока эта глиняная трубка зажжена, вы можете использовать действие, чтобы выпустить кольцо дыма из трубки.', '["Дымовые кольца","Требует настройки"]'),
('Каменный удачи', 'wondrous', 'uncommon', true, 0, 4200, 'Пока этот камень у вас, вы получаете бонус +1 к проверкам характеристик и спасброскам.', '["+1 ко всем проверкам","Требует настройки"]'),
('Перчатки карманника', 'wondrous', 'uncommon', true, 0, 1200, 'Пока эти перчатки надето, вы совершаете с преимуществом проверки Ловкости (Ловкость рук) и КД для проверок Ловкости (Ловкость рук), совершённых против вас, увеличивается на 5.', '["Преимущество на Ловкость рук","КД+5 против Ловкости рук","Требует настройки"]'),
('Мантия заклинателя', 'armor', 'very_rare', true, 4, 12000, 'Пока эта мантия настроена, вы получаете бонус +2 к броскам атаки заклинаниями и к СЛ спасбросков ваших заклинаний.', '["+2 к атаке заклинаниями","+2 к СЛ заклинаний","Требует настройки"]');
